#!/usr/bin/env bash\nset -euo pipefail\n\n# ============================================================================\n# VibeCode OS вЂ” РњР°СЃС‚РµСЂ СѓСЃС‚Р°РЅРѕРІРєРё РєРѕРјРїРѕРЅРµРЅС‚РѕРІ (Minimal в†’ Full)\n# ============================================================================\n# РРЅС‚РµСЂР°РєС‚РёРІРЅС‹Р№ СЃРєСЂРёРїС‚ РґР»СЏ РґРѕСѓСЃС‚Р°РЅРѕРІРєРё РєРѕРјРїРѕРЅРµРЅС‚РѕРІ РІ Minimal-РІРµСЂСЃРёРё\n# Р—Р°РїСѓСЃРєР°РµС‚СЃСЏ РІ СѓСЃС‚Р°РЅРѕРІР»РµРЅРЅРѕР№ СЃРёСЃС‚РµРјРµ!\n# ============================================================================\n\n# Р¦РІРµС‚Р°\nRED='\033[0;31m'\nGREEN='\033[0;32m'\nYELLOW='\033[1;33m'\nBLUE='\033[0;34m'\nCYAN='\033[0;36m'\nNC='\033[0m' # No Color\nBOLD='\033[1m'\n\n# РЎРёРјРІРѕР»С‹\nCHECK="вњ“"\nCROSS="вњ—"\nARROW="в†’"\n\n# РЎРѕСЃС‚РѕСЏРЅРёРµ СѓСЃС‚Р°РЅРѕРІРєРё\ndeclare -A INSTALLED=(\n    [terminal]=0\n    [shell]=0\n    [langs]=0\n    [editors]=0\n    [devtools]=0\n    [ai]=0\n    [nvidia]=0\n)\n\n# ============================================================================\n# РЈС‚РёР»РёС‚С‹\n# ============================================================================\n\nprint_header() {\n    clear\n    echo -e "${CYAN}"\n    echo "в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—"\n    echo "в•‘           VibeCode OS вЂ” РњР°СЃС‚РµСЂ СѓСЃС‚Р°РЅРѕРІРєРё                     в•‘"\n    echo "в•‘                    Minimal в†’ Full                            в•‘"\n    echo "в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ"\n    echo -e "${NC}"\n    echo ""\n}\n\nprint_section() {\n    echo -e "${BLUE}в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${NC}"\n    echo -e "${BOLD}$1${NC}"\n    echo -e "${BLUE}в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${NC}"\n}\n\nprint_option() {\n    local num="$1"\n    local desc="$2"\n    local status="$3"\n\n    if [[ "$status" == "installed" ]]; then\n        echo -e "  ${GREEN}[${CHECK}]${NC} ${num}. ${desc} ${GREEN}(СѓСЃС‚Р°РЅРѕРІР»РµРЅРѕ)${NC}"\n    elif [[ "$status" == "selected" ]]; then\n        echo -e "  ${YELLOW}[в–¶]${NC} ${num}. ${desc}"\n    else\n        echo -e "  ${CYAN}[ ]${NC} ${num}. ${desc}"\n    fi\n}\n\ncheck_root() {\n    if [[ $EUID -ne 0 ]]; then\n        echo -e "${RED}РћС€РёР±РєР°: Р—Р°РїСѓСЃС‚РёС‚Рµ РѕС‚ root (sudo)$${NC}"\n        exit 1\n    fi\n}\n\ncheck_network() {\n    curl -sf --connect-timeout 5 https://github.com >/dev/null 2>&1\n    return $?\n}\n\n# ============================================================================\n# РџСЂРѕРІРµСЂРєР° СѓСЃС‚Р°РЅРѕРІР»РµРЅРЅС‹С… РєРѕРјРїРѕРЅРµРЅС‚РѕРІ\n# ============================================================================\n\ncheck_installed() {\n    # РўРµСЂРјРёРЅР°Р» (Kitty)\n    if command -v kitty >/dev/null 2>&1; then\n        INSTALLED[terminal]=1\n    fi\n\n    # Shell (Zsh + Starship)\n    if command -v zsh >/dev/null 2>&1 && command -v starship >/dev/null 2>&1; then\n        INSTALLED[shell]=1\n    fi\n\n    # РЇР·С‹РєРё (pyenv, nvm, rustup)\n    if [[ -d "$HOME/.pyenv" ]] || [[ -d "$HOME/.nvm" ]] || [[ -d "$HOME/.cargo" ]]; then\n        INSTALLED[langs]=1\n    fi\n\n    # Р РµРґР°РєС‚РѕСЂС‹ (VSCodium, Neovim)\n    if command -v codium >/dev/null 2>&1 || command -v nvim >/dev/null 2>&1; then\n        INSTALLED[editors]=1\n    fi\n\n    # Devtools (Docker, lazygit)\n    if command -v docker >/dev/null 2>&1 || command -v lazygit >/dev/null 2>&1; then\n        INSTALLED[devtools]=1\n    fi\n\n    # AI (Ollama)\n    if command -v ollama >/dev/null 2>&1; then\n        INSTALLED[ai]=1\n    fi\n\n    # NVIDIA РґСЂР°Р№РІРµСЂС‹\n    if lspci | grep -i nvidia >/dev/null 2>&1 && nvidia-smi >/dev/null 2>&1; then\n        INSTALLED[nvidia]=1\n    fi\n}\n\nget_status() {\n    local key="$1"\n    if [[ "${INSTALLED[$key]}" == "1" ]]; then\n        echo "installed"\n    else\n        echo "pending"\n    fi\n}\n\n# ============================================================================\n# РњРµРЅСЋ\n# ============================================================================\n\nshow_main_menu() {\n    print_header\n    print_section "рџ“¦ Р’С‹Р±РµСЂРёС‚Рµ РєРѕРјРїРѕРЅРµРЅС‚С‹ РґР»СЏ СѓСЃС‚Р°РЅРѕРІРєРё:"\n    echo ""\n\n    print_option "1" "РўРµСЂРјРёРЅР°Р» Рё РѕР±РѕР»РѕС‡РєР° (Kitty, Zsh, Starship, CLI-СѓС‚РёР»РёС‚С‹)" "$(get_status terminal)"\n    print_option "2" "РЇР·С‹РєРё РїСЂРѕРіСЂР°РјРјРёСЂРѕРІР°РЅРёСЏ (Python, Node.js, Rust, Go, Java)" "$(get_status langs)"\n    print_option "3" "Р РµРґР°РєС‚РѕСЂС‹ Рё IDE (VSCodium, Neovim, Zed)" "$(get_status editors)"\n    print_option "4" "РРЅСЃС‚СЂСѓРјРµРЅС‚С‹ СЂР°Р·СЂР°Р±РѕС‚С‡РёРєР° (Git, Docker, lazygit)" "$(get_status devtools)"\n    print_option "5" "AI-СЃС‚РµРє (Ollama, Open WebUI, ai-chat, ComfyUI)" "$(get_status ai)"\n    print_option "6" "Р”СЂР°Р№РІРµСЂС‹ NVIDIA" "$(get_status nvidia)"\n    echo ""\n    print_option "A" "РЈСЃС‚Р°РЅРѕРІРёС‚СЊ Р’РЎРЃ (Full РІРµСЂСЃРёСЏ)" ""\n    print_option "R" "РџРµСЂРµРїСЂРѕРІРµСЂРёС‚СЊ СѓСЃС‚Р°РЅРѕРІР»РµРЅРЅС‹Рµ РєРѕРјРїРѕРЅРµРЅС‚С‹" ""\n    print_option "0" "Р’С‹С…РѕРґ" ""\n    echo ""\n    echo -e "${YELLOW}Р’РІРµРґРёС‚Рµ РЅРѕРјРµСЂ РєРѕРјРїРѕРЅРµРЅС‚Р° (РёР»Рё РЅРµСЃРєРѕР»СЊРєРѕ С‡РµСЂРµР· РїСЂРѕР±РµР»):${NC}"\n}\n\n# ============================================================================\n# РЈСЃС‚Р°РЅРѕРІРєР° РєРѕРјРїРѕРЅРµРЅС‚РѕРІ\n# ============================================================================\n\ninstall_terminal() {\n    print_header\n    echo -e "${GREEN}рџ“¦ РЈСЃС‚Р°РЅРѕРІРєР° С‚РµСЂРјРёРЅР°Р»Р° Рё РѕР±РѕР»РѕС‡РєРё...${NC}"\n    echo ""\n\n    echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Kitty...${NC}"\n    apt-get update -qq\n    apt-get install -y kitty\n\n    echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° С€СЂРёС„С‚РѕРІ...${NC}"\n    apt-get install -y fonts-jetbrains-mono fonts-fira-code fonts-hack\n\n    echo -e "${CYAN}РќР°СЃС‚СЂРѕР№РєР° Zsh...${NC}"\n    apt-get install -y zsh\n\n    # Oh My Zsh\n    if [[ ! -d "$HOME/.oh-my-zsh" ]]; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Oh My Zsh...${NC}"\n        sh -c "$(curl -fsSL https://raw.githubusercontent.com/ohmyzsh/ohmyzsh/master/tools/install.sh)" "" --unattended || true\n    fi\n\n    # Starship\n    if ! command -v starship &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Starship...${NC}"\n        curl -sS https://starship.rs/install.sh | sh -s -- -y || true\n    fi\n\n    # CLI-СѓС‚РёР»РёС‚С‹\n    echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° CLI-СѓС‚РёР»РёС‚...${NC}"\n    apt-get install -y eza bat fd-find ripgrep fzf zoxide btop\n\n    # РСЃРїСЂР°РІР»РµРЅРёРµ РёРјС‘РЅ (Ubuntu)\n    ln -sf /usr/bin/batcat /usr/local/bin/bat 2>/dev/null || true\n    ln -sf /usr/bin/fdfind /usr/local/bin/fd 2>/dev/null || true\n\n    # РЈСЃС‚Р°РЅРѕРІРєР° Zsh РїРѕ СѓРјРѕР»С‡Р°РЅРёСЋ\n    chsh -s $(which zsh) 2>/dev/null || true\n\n    echo ""\n    echo -e "${GREEN}${CHECK} РўРµСЂРјРёРЅР°Р» Рё РѕР±РѕР»РѕС‡РєР° СѓСЃС‚Р°РЅРѕРІР»РµРЅС‹!${NC}"\n    echo ""\n    read -p "РќР°Р¶РјРёС‚Рµ Enter РґР»СЏ РїСЂРѕРґРѕР»Р¶РµРЅРёСЏ..."\n}\n\ninstall_langs() {\n    print_header\n    echo -e "${GREEN}рџ“¦ РЈСЃС‚Р°РЅРѕРІРєР° СЏР·С‹РєРѕРІ РїСЂРѕРіСЂР°РјРјРёСЂРѕРІР°РЅРёСЏ...${NC}"\n    echo ""\n\n    # Р—Р°РІРёСЃРёРјРѕСЃС‚Рё\n    echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Р·Р°РІРёСЃРёРјРѕСЃС‚РµР№...${NC}"\n    apt-get update -qq\n    apt-get install -y build-essential curl git ca-certificates libssl-dev zlib1g-dev \\n        libbz2-dev libreadline-dev libsqlite3-dev wget llvm libncursesw5-dev xz-utils \\n        tk-dev libxml2-dev libxmlsec1-dev libffi-dev liblzma-dev\n\n    # Pyenv\n    if [[ ! -d "$HOME/.pyenv" ]]; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° pyenv...${NC}"\n        curl -fsSL https://github.com/pyenv/pyenv-installer/raw/master/bin/pyenv-installer | bash || true\n\n        # Р”РѕР±Р°РІР»СЏРµРј РІ .zshrc\n        if [[ -f "$HOME/.zshrc" ]] && ! grep -q "pyenv init" "$HOME/.zshrc"; then\n            cat >> "$HOME/.zshrc" << 'PYEOF'\nexport PYENV_ROOT="$HOME/.pyenv"\n[[ -d $PYENV_ROOT/bin ]] && export PATH="$PYENV_ROOT/bin:$PATH"\neval "$(pyenv init -)"\nPYEOF\n        fi\n    fi\n\n    # NVM\n    if [[ ! -d "$HOME/.nvm" ]]; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° nvm...${NC}"\n        curl -o- https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.4/install.sh | bash || true\n    fi\n\n    # Rustup\n    if [[ ! -d "$HOME/.cargo" ]]; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° rustup...${NC}"\n        curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh -s -- -y || true\n    fi\n\n    # SDKMAN\n    if [[ ! -d "$HOME/.sdkman" ]]; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° SDKMAN!...${NC}"\n        curl -s "https://get.sdkman.io" | bash || true\n    fi\n\n    # Go\n    if ! command -v go &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Go...${NC}"\n        apt-get install -y golang-go || true\n    fi\n\n    echo ""\n    echo -e "${GREEN}${CHECK} РЇР·С‹РєРё СѓСЃС‚Р°РЅРѕРІР»РµРЅС‹! РџРµСЂРµР·Р°Р№РґРёС‚Рµ РІ С‚РµСЂРјРёРЅР°Р» РґР»СЏ РїСЂРёРјРµРЅРµРЅРёСЏ.${NC}"\n    read -p "РќР°Р¶РјРёС‚Рµ Enter РґР»СЏ РїСЂРѕРґРѕР»Р¶РµРЅРёСЏ..."\n}\n\ninstall_editors() {\n    print_header\n    echo -e "${GREEN}рџ“¦ РЈСЃС‚Р°РЅРѕРІРєР° СЂРµРґР°РєС‚РѕСЂРѕРІ Рё IDE...${NC}"\n    echo ""\n\n    # VSCodium\n    if ! command -v codium &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° VSCodium...${NC}"\n        wget -qO - https://gitlab.com/paulcarroty/vscodium-deb-rpm-repo/raw/master/pub.gpg | gpg --dearmor > /usr/share/keyrings/vscodium-archive-keyring.gpg 2>/dev/null || true\n        echo 'deb [ signed-by=/usr/share/keyrings/vscodium-archive-keyring.gpg ] https://download.vscodium.com/debs vscodium main' | tee /etc/apt/sources.list.d/vscodium.list >/dev/null\n        apt-get update -qq\n        apt-get install -y codium || true\n    fi\n\n    # Neovim\n    if ! command -v nvim &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Neovim...${NC}"\n        apt-get install -y neovim || true\n    fi\n\n    # AstroNvim\n    if [[ ! -d "$HOME/.config/nvim" ]]; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° AstroNvim...${NC}"\n        git clone --depth 1 https://github.com/AstroNvim/template "$HOME/.config/nvim" 2>/dev/null && rm -rf "$HOME/.config/nvim/.git" || true\n    fi\n\n    # Zed\n    if ! command -v zed &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Zed...${NC}"\n        curl -f https://zed.dev/install.sh | sh || true\n    fi\n\n    echo ""\n    echo -e "${GREEN}${CHECK} Р РµРґР°РєС‚РѕСЂС‹ СѓСЃС‚Р°РЅРѕРІР»РµРЅС‹!${NC}"\n    read -p "РќР°Р¶РјРёС‚Рµ Enter РґР»СЏ РїСЂРѕРґРѕР»Р¶РµРЅРёСЏ..."\n}\n\ninstall_devtools() {\n    print_header\n    echo -e "${GREEN}рџ“¦ РЈСЃС‚Р°РЅРѕРІРєР° РёРЅСЃС‚СЂСѓРјРµРЅС‚РѕРІ СЂР°Р·СЂР°Р±РѕС‚С‡РёРєР°...${NC}"\n    echo ""\n\n    # Git\n    if ! command -v git &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Git...${NC}"\n        apt-get install -y git || true\n    fi\n\n    # lazygit\n    if ! command -v lazygit &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° lazygit...${NC}"\n        LAZYGIT_VERSION=$(curl -s "https://api.github.com/repos/jesseduffield/lazygit/releases/latest" | grep -oP '"tag_name": "v\K[^"]*' 2>/dev/null || echo "")\n        if [[ -n "$LAZYGIT_VERSION" ]]; then\n            curl -Lo /tmp/lazygit.tar.gz "https://github.com/jesseduffield/lazygit/releases/latest/download/lazygit_${LAZYGIT_VERSION}_Linux_x86_64.tar.gz" 2>/dev/null || true\n            tar xf /tmp/lazygit.tar.gz -C /tmp lazygit 2>/dev/null || true\n            install /tmp/lazygit /usr/local/bin/lazygit 2>/dev/null || true\n            rm -f /tmp/lazygit /tmp/lazygit.tar.gz\n        fi\n    fi\n\n    # Docker\n    if ! command -v docker &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Docker...${NC}"\n        apt-get install -y docker.io docker-compose-plugin || true\n        systemctl enable docker 2>/dev/null || true\n        systemctl start docker 2>/dev/null || true\n    fi\n\n    # Р”РѕР±Р°РІР»СЏРµРј РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ РІ РіСЂСѓРїРїСѓ docker\n    usermod -aG docker "$USER" 2>/dev/null || true\n\n    echo ""\n    echo -e "${GREEN}${CHECK} РРЅСЃС‚СЂСѓРјРµРЅС‚С‹ СѓСЃС‚Р°РЅРѕРІР»РµРЅС‹!${NC}"\n    echo -e "${YELLOW}вљ пёЏ  Р”Р»СЏ СЂР°Р±РѕС‚С‹ Docker РјРѕР¶РµС‚ РїРѕС‚СЂРµР±РѕРІР°С‚СЊСЃСЏ РїРµСЂРµР·Р°РіСЂСѓР·РєР°.${NC}"\n    read -p "РќР°Р¶РјРёС‚Рµ Enter РґР»СЏ РїСЂРѕРґРѕР»Р¶РµРЅРёСЏ..."\n}\n\ninstall_ai() {\n    print_header\n    echo -e "${GREEN}рџ“¦ РЈСЃС‚Р°РЅРѕРІРєР° AI-СЃС‚РµРєР°...${NC}"\n    echo ""\n    echo -e "${YELLOW}вљ пёЏ  Р’РЅРёРјР°РЅРёРµ: AI-СЃС‚РµРє С‚СЂРµР±СѓРµС‚ РјРЅРѕРіРѕ РјРµСЃС‚Р° (~10-20 Р“Р‘)${NC}"\n    echo ""\n    read -p "РџСЂРѕРґРѕР»Р¶РёС‚СЊ? (y/n): " -n 1 -r\n    echo\n\n    if [[ ! $REPLY =~ ^[Yy]$ ]]; then\n        echo -e "${YELLOW}РџСЂРѕРїСѓС‰РµРЅРѕ${NC}"\n        read -p "РќР°Р¶РјРёС‚Рµ Enter РґР»СЏ РїСЂРѕРґРѕР»Р¶РµРЅРёСЏ..."\n        return\n    fi\n\n    # Ollama\n    if ! command -v ollama &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Ollama...${NC}"\n        curl -fsSL https://ollama.com/install.sh | sh || true\n        systemctl enable ollama 2>/dev/null || true\n        systemctl start ollama 2>/dev/null || true\n    fi\n\n    # Open WebUI (Docker)\n    if command -v docker &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Open WebUI...${NC}"\n        docker run -d --name open-webui -p 3000:8080 --add-host=host.docker.internal:host-gateway -v open-webui:/app/backend/data --restart always ghcr.io/open-webui/open-webui:main 2>/dev/null || true\n    fi\n\n    # ai-chat (Р»РѕРєР°Р»СЊРЅС‹Р№ СЃРєСЂРёРїС‚)\n    if [[ ! -f /usr/local/bin/ai-chat ]]; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° ai-chat...${NC}"\n        # РџСЂРѕСЃС‚РѕР№ СЃРєСЂРёРїС‚ РґР»СЏ С‡Р°С‚Р° СЃ Ollama\n        cat > /usr/local/bin/ai-chat << 'AIEOF'\n#!/usr/bin/env bash\nMODEL="${1:-llama3.2}"\necho "AI Chat (РјРѕРґРµР»СЊ: $MODEL). Р’РІРµРґРёС‚Рµ /exit РґР»СЏ РІС‹С…РѕРґР°."\nwhile true; do\n    read -p "> " prompt\n    [[ "$prompt" == "/exit" ]] && break\n    [[ -z "$prompt" ]] && continue\n    ollama chat "$MODEL" -m "$prompt" 2>/dev/null || echo "РћС€РёР±РєР°: ollama РЅРµ Р·Р°РїСѓС‰РµРЅР°"\ndone\nAIEOF\n        chmod +x /usr/local/bin/ai-chat\n    fi\n\n    # Aider\n    if ! command -v aider &>/dev/null; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Aider...${NC}"\n        pip3 install aider-chat || true\n    fi\n\n    # Python AI-Р±РёР±Р»РёРѕС‚РµРєРё\n    echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° Python AI-Р±РёР±Р»РёРѕС‚РµРє...${NC}"\n    pip3 install langchain langchain-community llama-index transformers accelerate ollama 2>/dev/null || true\n\n    # ComfyUI\n    if [[ ! -d "$HOME/ComfyUI" ]]; then\n        echo -e "${CYAN}РЈСЃС‚Р°РЅРѕРІРєР° ComfyUI...${NC}"\n        cd "$HOME" && git clone https://github.com/comfyanonymous/ComfyUI.git 2>/dev/null || true\n    fi\n\n    echo ""\n    echo -e "${GREEN}${CHECK} AI-СЃС‚РµРє СѓСЃС‚Р°РЅРѕРІР»РµРЅ!${NC}"\n    echo ""\n    echo -e "${CYAN}Р‘С‹СЃС‚СЂС‹Р№ СЃС‚Р°СЂС‚:${NC}"\n    echo "  вЂў Open WebUI: http://localhost:3000"\n    echo "  вЂў Terminal: ai-chat"\n    echo "  вЂў ComfyUI: cd ~/ComfyUI && python main.py"\n    read -p "РќР°Р¶РјРёС‚Рµ Enter РґР»СЏ РїСЂРѕРґРѕР»Р¶РµРЅРёСЏ..."\n}\n\ninstall_nvidia() {\n    print_header\n    echo -e "${GREEN}рџ“¦ РЈСЃС‚Р°РЅРѕРІРєР° РґСЂР°Р№РІРµСЂРѕРІ NVIDIA...${NC}"\n    echo ""\n\n    # РџСЂРѕРІРµСЂРєР° РЅР°Р»РёС‡РёСЏ NVIDIA GPU\n    if ! lspci | grep -i nvidia >/dev/null 2>&1; then\n        echo -e "${YELLOW}вљ пёЏ  Р’РёРґРµРѕРєР°СЂС‚Р° NVIDIA РЅРµ РЅР°Р№РґРµРЅР°. РџСЂРѕРїСѓСЃРєР°РµРј.${NC}"\n        read -p "РќР°Р¶РјРёС‚Рµ Enter РґР»СЏ РїСЂРѕРґРѕР»Р¶РµРЅРёСЏ..."\n        return\n    fi\n\n    echo -e "${CYAN}РћР±РЅР°СЂСѓР¶РµРЅР° РІРёРґРµРѕРєР°СЂС‚Р° NVIDIA. РЈСЃС‚Р°РЅРѕРІРєР° РґСЂР°Р№РІРµСЂРѕРІ...${NC}"\n\n    # Р”РѕР±Р°РІР»СЏРµРј СЂРµРїРѕР·РёС‚РѕСЂРёР№ NVIDIA\n    add-apt-repository -y ppa:graphics-drivers/ppa 2>/dev/null || true\n    apt-get update -qq\n\n    # РЈСЃС‚Р°РЅРѕРІРєР° РґСЂР°Р№РІРµСЂР°\n    apt-get install -y nvidia-driver-535 nvidia-utils-535 || true\n\n    echo ""\n    echo -e "${GREEN}${CHECK} Р”СЂР°Р№РІРµСЂС‹ СѓСЃС‚Р°РЅРѕРІР»РµРЅС‹!${NC}"\n    echo -e "${YELLOW}вљ пёЏ  РўСЂРµР±СѓРµС‚СЃСЏ РїРµСЂРµР·Р°РіСЂСѓР·РєР° РґР»СЏ РїСЂРёРјРµРЅРµРЅРёСЏ.${NC}"\n    read -p "РќР°Р¶РјРёС‚Рµ Enter РґР»СЏ РїСЂРѕРґРѕР»Р¶РµРЅРёСЏ..."\n}\n\ninstall_all() {\n    print_header\n    echo -e "${GREEN}рџ“¦ РЈСЃС‚Р°РЅРѕРІРєР° Р’РЎР•РҐ РєРѕРјРїРѕРЅРµРЅС‚РѕРІ (Full РІРµСЂСЃРёСЏ)...${NC}"\n    echo ""\n    echo -e "${YELLOW}вљ пёЏ  Р­С‚Рѕ Р·Р°Р№РјС‘С‚ РІСЂРµРјСЏ Рё РїРѕС‚СЂРµР±СѓРµС‚ РјРЅРѕРіРѕ РјРµСЃС‚Р° (~20-30 Р“Р‘)${NC}"\n    echo ""\n    read -p "РџСЂРѕРґРѕР»Р¶РёС‚СЊ? (y/n): " -n 1 -r\n    echo\n\n    if [[ ! $REPLY =~ ^[Yy]$ ]]; then\n        echo -e "${YELLOW}РћС‚РјРµРЅРµРЅРѕ${NC}"\n        read -p "РќР°Р¶РјРёС‚Рµ Enter РґР»СЏ РїСЂРѕРґРѕР»Р¶РµРЅРёСЏ..."\n        return\n    fi\n\n    install_terminal\n    install_langs\n    install_editors\n    install_devtools\n    install_ai\n    install_nvidia\n\n    print_header\n    echo -e "${GREEN}${CHECK} Р’СЃРµ РєРѕРјРїРѕРЅРµРЅС‚С‹ СѓСЃС‚Р°РЅРѕРІР»РµРЅС‹!${NC}"\n    echo ""\n    echo "рџЋ‰ VibeCode OS Full РіРѕС‚РѕРІР° Рє СЂР°Р±РѕС‚Рµ!"\n    echo ""\n    echo -e "${CYAN}Р РµРєРѕРјРµРЅРґСѓРµС‚СЃСЏ РїРµСЂРµР·Р°РіСЂСѓР·РёС‚СЊ СЃРёСЃС‚РµРјСѓ.${NC}"\n    read -p "РќР°Р¶РјРёС‚Рµ Enter РґР»СЏ РїСЂРѕРґРѕР»Р¶РµРЅРёСЏ..."\n}\n\n# ============================================================================\n# РћСЃРЅРѕРІРЅР°СЏ Р»РѕРіРёРєР°\n# ============================================================================\n\nmain() {\n    check_root\n\n    # РћРїСЂРµРґРµР»СЏРµРј С‚РµРєСѓС‰РµРіРѕ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ (РЅРµ root)\n    if [[ -n "${SUDO_USER:-}" ]]; then\n        USER="$SUDO_USER"\n    else\n        USER="$(whoami)"\n    fi\n    HOME="/home/$USER"\n\n    # РџСЂРёРІРµС‚СЃС‚РІРёРµ\n    print_header\n    echo -e "${CYAN}Р”РѕР±СЂРѕ РїРѕР¶Р°Р»РѕРІР°С‚СЊ РІ VibeCode OS Minimal!${NC}"\n    echo ""\n    echo "Р­С‚РѕС‚ РјР°СЃС‚РµСЂ РїРѕРјРѕР¶РµС‚ РІР°Рј РґРѕСѓСЃС‚Р°РЅРѕРІРёС‚СЊ РєРѕРјРїРѕРЅРµРЅС‚С‹ РґРѕ Full-РІРµСЂСЃРёРё."\n    echo ""\n    echo -e "${YELLOW}РЎРѕРІРµС‚: РЎРЅР°С‡Р°Р»Р° РІС‹Р±РµСЂРёС‚Рµ 'R' РґР»СЏ РїСЂРѕРІРµСЂРєРё СѓСЃС‚Р°РЅРѕРІР»РµРЅРЅС‹С… РєРѕРјРїРѕРЅРµРЅС‚РѕРІ.${NC}"\n    echo ""\n    sleep 2\n\n    while true; do\n        check_installed\n        show_main_menu\n\n        read -r input\n\n        case "$input" in\n            1)\n                install_terminal\n                ;;\n            2)\n                install_langs\n                ;;\n            3)\n                install_editors\n                ;;\n            4)\n                install_devtools\n                ;;\n            5)\n                install_ai\n                ;;\n            6)\n                install_nvidia\n                ;;\n            [Aa])\n                install_all\n                ;;\n            [Rr])\n                check_installed\n                echo -e "${GREEN}вњ“ РџСЂРѕРІРµСЂРєР° РІС‹РїРѕР»РЅРµРЅР°!${NC}"\n                sleep 1\n                ;;\n            [Qq0])\n                print_header\n                echo -e "${GREEN}РЎРїР°СЃРёР±Рѕ Р·Р° РёСЃРїРѕР»СЊР·РѕРІР°РЅРёРµ VibeCode OS!${NC}"\n                echo ""\n                exit 0\n                ;;\n            *)\n                # РћР±СЂР°Р±РѕС‚РєР° РЅРµСЃРєРѕР»СЊРєРёС… С†РёС„СЂ С‡РµСЂРµР· РїСЂРѕР±РµР»\n                for num in $input; do\n                    case "$num" in\n                        1) install_terminal ;;\n                        2) install_langs ;;\n                        3) install_editors ;;\n                        4) install_devtools ;;\n                        5) install_ai ;;\n                        6) install_nvidia ;;\n                    esac\n                done\n                ;;\n        esac\n    done\n}\n\n# Р—Р°РїСѓСЃРє\nmain\n